# testZRPythonExpr.py
""" Unit tests for Products.PageTemplates.ZRPythonExpr

$Id
"""
import unittest
from Products.PageTemplates.ZRPythonExpr import PythonExpr

class PythonExprTests(unittest.TestCase):

    def _makeOne(self, expr):
        return PythonExpr(expr)

    def test_simple_expression(self):
        expr = self._makeOne('"hello world"')
        result = expr()
        self.assertEqual(result, 'hello world')

    def test_expression_with_context(self):
        context = {'greeting' : 'hello world'}
        expr = self._makeOne('greeting')
        result = expr(context)
        self.assertEqual(result, 'hello world')

    def test_expression_with_here(self):
        here = {'greeting' : 'hello world'}
        expr = self._makeOne('greeting')
        result = expr({}, here)
        self.assertEqual(result, 'hello world')

    def test_expression_with_request(self):
        request = {'greeting' : 'hello world'}
        expr = self._makeOne('greeting')
        result = expr({}, {}, request)
        self.assertEqual(result, 'hello world')

    def test_expression_with_nothing(self):
        expr = self._makeOne('greeting')
        result = expr()
        self.assertEqual(result, None)


def test_suite():
    return unittest.makeSuite(PythonExprTests)

if __name__ == '__main__':
    unittest.main(defaultTest='test_suite')

