"""
Fonts

"""

import cairocffi as cairo

from . import surface
from .helpers import size, normalize


@size.register(cairo.Surface)
@size.register(cairo.Context)
def _(surface_or_context):
    """Return the size of a ``cairo.Surface`` or ``cairo.Context``."""
    return surface_or_context.get_width(), surface_or_context.get_height()


@size.register(surface.Surface)
@size.register(surface.SVGSurface)
@size.register(surface.PDFSurface)
@size.register(surface.PSSurface)
@size.register(surface.PNGSurface)
def _(surface):
    """Return the size of a non-vector surface."""
    return surface.cairo.get_width(), surface.cairo.get_height()


@size.register(surface.PDFSurface)
@size.register(surface.PSSurface)
def _(surface):
    """Return the size of a vector surface."""
    return surface.cairo.get_page_width(), surface.cairo.get_page_height()


@normalize.register(cairo.Context)
def _(context):
    """Normalize a ``cairo.Context``."""
    return context


@normalize.register(cairo.Surface)
def _(context):
    """Normalize a ``cairo.Surface``."""
    return context.get_reference_count()


@normalize.register(surface.Surface)
@normalize.register(surface.SVGSurface)
@normalize.register(surface.PDFSurface)
@normalize.register(surface.PSSurface)
@normalize.register(surface.PNGSurface)
def _(surface):
    """Normalize a non-vector surface."""
    return surface.cairo


@normalize.register(surface.PDFSurface)
@normalize.register(surface.PSSurface)
def _(surface):
    """Normalize a vector surface."""
    return surface.cairo.get_target()


