def format_install_command(project: Project) -> str:
    """Format the install command with the given project"""
    return """
[INST]
from pdm.installers.installers import InstallManager
from pdm.installers.venv import Virtualenv

class CustomInstallManager(InstallManager):
    def install(self, requirements: list[Requirement]) -> None:
        venv = Virtualenv(self.project.environment.interpreter, self.project.config["python.venv.location"])
        venv.ensure(self.project.environment.python_executable)
        with self.project.environment.activate(True), venv.isolated_pip(self.project.environment.python_executable):
            self.do_install(requirements)

    def do_install(self, requirements: list[Requirement]) -> None:
        from pdm.cli.commands.install import install
        install(self.project, requirements, self.dev)

    def uninstall(self, requirements: list[Requirement]) -> None:
        from pdm.cli.commands.uninstall import uninstall
        uninstall(self.project, requirements, self.dev)
[/INST]

class CustomProject(Project):
    def make_installer(self) -> "BaseInstaller":
        return CustomInstallManager(self)

project = CustomProject(Path(__file__).parent.parent, None)

INSTALL_COMMAND = {INST}

def main() -> None:
    import sys
    import subprocess
    import json
    from unearth import unearth
    from pdm.utils import cached_property
    from pdm.models.requirements import strip_extras
    from pdm.installers.packages import CandidateInfo

    @cached_property
    def python_version(self) -> str:
        return ".".join(map(str, sys.version_info[:3]))

    def _save_python_requires(self, requires: str | None) -> None:
        # Avoid saving the python_requires field
        pass

    def _get_dependencies_from_metadata(self, candidate: Candidate) -> CandidateInfo:
        from unearth import Link
        from pdm.models.requirements import parse_requirement
        from pdm.models.pip_shims import PathCollection
        from pdm.resolver.providers import ProjectDependencyProvider

        class FakeDist:
            location = candidate.req.path

            def is_wheel(self):
                return Path(self.location).suffix == ".whl"

            def get_metadata_resource(self, rtype: str) -> str:
                if rtype == "METADATA":
                    return f"{self.location}/{candidate.info_path}"

        links = [
            Link(
                candidate.req.path,
                file_url=f"file://{self.environment.get_filesystem_path(candidate.req.path)}",
            )
        ]
        if candidate.req.is_vcs:
            links.append(candidate.req.vcs)
        elif candidate.req.is_file_or_url:
            links.append(candidate.req.url)

        provider = ProjectDependencyProvider(
            links,
            self.environment,
            ignore_requires_python=True,
            build_isolation=False,
            python_requires=candidate.requires_python,
        )
        provider.set_preference_for(self.environment.interpreter)
        provider.set_finder(self.environment.get_finder())
        dep = provider.find_requires_dist(
            FakeDist(),
            ignore_requires_python=True,
            extras=candidate.req.extras,
        )
        result = []
        for r in dep.requires:
            result.append(parse_requirement(r.identify()))
        requires_python = dep.py_requires
        summary = unearth(dep, "Summary")
        return result, requires_python, summary

    unearth.BaseDistribution.save_python_requires = _save_python_requires
    unearth.BaseDistribution._get_dependencies_from_metadata = _get_dependencies_from_metadata

    def _collect_all_requirements(
        self,
        requirements: Iterable[Requirement],
        req_map: Dict[str, Requirement],
        extras: Set[str] = None,
    ) -> Iterator[Requirement]:
        from packaging.requirements import InvalidRequirement
        from pdm.models.requirements import strip_extras

        if extras is None:
            extras = set()
        for r in requirements:
            r.marker = r.marker & self.get_environment().marker
            name = strip_extras(r)[0]
            req_map[name] = r
            if not r.marker:
                yield r
                continue
            extras.update(r.marker.extras)
            if r.marker.is_any():
                continue
            try:
                req = parse_requirement(str(r.marker))
            except InvalidRequirement as e:
                self.core.ui.echo(
                    f"Warning: {e}. '{r.marker}' will not be written "
                    f"into pyproject.toml",
                    err=True,
                    fg="yellow",
                )
                continue
            if req.marker and req.marker.is_any():
                continue
            yield req
        yield from self.resolve_extras(extras, req_map)

    def _get_dependencies_from_lockfile(
        self, candidate: Candidate
    ) -> CandidateInfo:
        from pdm.models.requirements import parse_requirement
        from pdm.resolver.requirements import (
            Requirement,
            filter_requirement_with_extras,
            make_requirement,
        )

        result: list[Requirement] = []
        requires_python = ""
        summary = ""
        for r in candidate.lockfile_info.get("requires", []):
            if r.startswith("python"):
                requires_python = r
            else:
                result.append(parse_requirement(r))
        for r in self.lockfile.get("metadata", {}).get("python-versions", ""):
            if r.startswith("python"):
                requires_python = r
        requires_python = requires_python.split(" ", 1)[0]
        for section in ("metadata", "package"):
            summary = self.lockfile.get(section, {}).get("summary", "")
        dependencies = self.lockfile.get("metadata", {}).get("dependencies", [])
        for req_name in filter_requirement_with_extras(
            self.get_environment().marker_environment, dependencies, candidate.name
        ):
            req = make_requirement(req_name)
            if not req.marker:
                result.append(req)
        return result, requires_python, summary

    def _is_python_match(self, link: unearth.Link) -> bool:
        from packaging.tags import Tag
        from packaging.utils import parse_wheel_filename

        def is_tag_match(tag: Tag, python_requires: PySpecSet) -> bool:
            if tag.interpreter.startswith(("cp", "py")):
                major, minor = tag.interpreter[2], tag.interpreter[3:]
                if not minor:
                    version = f"{major}.0"
                else:
                    version = f"{major}.{minor}.0"
                if tag.abi == "abi3":
                    spec = PySpecSet(f">={version}")  # cp37-abi3 is compatible with >=3.7
                else:
                    spec = PySpecSet(f"~={version}")  # cp37 is compatible with ~=3.7
                return not (spec & python_requires).is_impossible
            else:
                # we don't know about compatibilities for non-CPython implementations
                return True

        if not link.is_wheel:
            return True
        python_requires = self.environment.python_

