import datetime
from .models import Employee, Task
from .forms import *
from django.views.decorators.csrf import csrf_exempt  # To Disable CSRF
from django.contrib.auth.decorators import login_required
from django.http import HttpResponseRedirect
from django.urls import reverse
from django.contrib import messages
import logging
from django.conf import settings
from .email import send_forget_password_OTP
from threading import Thread

# Get an instance of a logger
logger = logging.getLogger(__name__)


@login_required
def addTask(request):
    form = TaskForm()
    if request.method == 'POST':
        form = TaskForm(request.POST)
        if form.is_valid():
            form.save()
            # thread = Thread(target = send_forget_password_OTP, args= (request,))
            # thread.start()
            return HttpResponseRedirect(reverse('CalendarinhoApp:Dashboard'))
    else:
        return render(request, 'CalendarinhoApp/addTask.html', {'form': form})


@login_required
def deleteTask(request, task_id):
    task = Task.objects.get(pk=task_id)
    task.delete()
    return HttpResponseRedirect(reverse('CalendarinhoApp:Dashboard'))


@login_required
def editTask(request, task_id):
    task = Task.objects.get(pk=task_id)
    form = TaskEditForm(instance=task)
    if request.method == 'POST':
        form = TaskEditForm(request.POST, instance=task)
        if form.is_valid():
            form.save()
            return HttpResponseRedirect(reverse('CalendarinhoApp:Dashboard'))
    else:
        return render(request, 'CalendarinhoApp/editTask.html', {'form': form})


@login_required
def calendar(request):
    today = datetime.datetime.today()
    taskList = Task.objects.filter(Date=today)
    return render(request, 'CalendarinhoApp/calendar.html', {'taskList': taskList})


@login_required
def dashboard(request):
    today = datetime.datetime.today()
    tomorrow = today + datetime.timedelta(days=1)
    taskList = Task.objects.filter(
        Date__range=(today, tomorrow), Status=0)
    return render(request, 'CalendarinhoApp/dashboard.html', {'taskList': taskList})


@login_required
def allTask(request):
    taskList = Task.objects.all()
    return render(request, 'CalendarinhoApp/allTask.html', {'taskList': taskList})


@login_required
def doneTask(request):
    taskList = Task.objects.filter(Status=1)
    return render(request, 'CalendarinhoApp/doneTask.html', {'taskList': taskList})


@login_required
def undoneTask(request):
    taskList = Task.objects.filter(Status=0)
    return render(request, 'CalendarinhoApp/undoneTask.html', {'taskList': taskList})
